function m(o,e){if(!o?.name||!e?.name)return{emotion:0,communication:0,passion:0,stability:0,total:0};let n=[o.name,o.birthDate||"",e.name,e.birthDate||""].join("|").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase(),t=0;for(let a=0;a<n.length;a++)t=(t*31+n.charCodeAt(a))%9973;let i=55+t*3%41,c=55+t*7%41,r=55+t*5%41,s=55+t*11%41,l=Math.floor((i+c+r+s)/4);return{emotion:i,communication:c,passion:r,stability:s,total:l}}export{m as calculateSynastryScores};
